-- ============================================================================
-- CICTrix full data reset from RSP HRMO Dataset Report (generated).
-- Additive schema only (new tables + NULLABLE columns) — no existing
-- table/column is dropped or altered destructively, so app code keeps working.
-- Then TRUNCATE ... CASCADE wipes ALL data and reloads the dataset.
-- Run this once in the Supabase SQL Editor. Back up first — this is destructive.
-- ============================================================================

-- New reference tables (natural text IDs, no FK remap needed).
CREATE TABLE IF NOT EXISTS divisions (
  id            text PRIMARY KEY,
  department_id text,
  department    text,
  division_name text
);
CREATE TABLE IF NOT EXISTS archives (
  id              text PRIMARY KEY,
  record_type     text,
  name            text,
  gender          text,
  related_position text,
  department      text,
  final_status    text,
  date_archived   date
);
CREATE TABLE IF NOT EXISTS applicant_scores (
  id               uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  applicant_ref    text,
  job_ref          text,
  applicant_name   text,
  exam_schedule    text,
  interview_schedule text,
  educ             integer,
  exp              integer,
  perf             integer,
  written          integer,
  potential        integer,
  pcpt             integer,
  oral             integer,
  overall_rating   numeric(4,2),
  status           text
);
CREATE TABLE IF NOT EXISTS exam_interview_schedules (
  id             uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  job_ref        text,
  applicant_ref  text,
  applicant_name text,
  schedule_type  text,
  sched_date     date,
  sched_time     text,
  venue          text
);

-- Nullable columns added to existing tables to fit the dataset.
ALTER TABLE departments  ADD COLUMN IF NOT EXISTS department_head_name text;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS division text;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS supervisor text;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS salary_grade text;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS employment_status text;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS no_of_vacancies integer;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS date_posted date;
ALTER TABLE job_postings ADD COLUMN IF NOT EXISTS application_deadline date;
ALTER TABLE applicants   ADD COLUMN IF NOT EXISTS applicant_ref text;
ALTER TABLE applicants   ADD COLUMN IF NOT EXISTS additional_months integer;
ALTER TABLE employees    ADD COLUMN IF NOT EXISTS division text;
ALTER TABLE employees    ADD COLUMN IF NOT EXISTS highest_educational_attainment text;
ALTER TABLE employees    ADD COLUMN IF NOT EXISTS eligibility text;

-- Frontend anon client access for the new tables (matches existing pattern).
ALTER TABLE divisions DISABLE ROW LEVEL SECURITY;
GRANT SELECT, INSERT, UPDATE, DELETE ON divisions TO authenticated, anon;
ALTER TABLE archives DISABLE ROW LEVEL SECURITY;
GRANT SELECT, INSERT, UPDATE, DELETE ON archives TO authenticated, anon;
ALTER TABLE applicant_scores DISABLE ROW LEVEL SECURITY;
GRANT SELECT, INSERT, UPDATE, DELETE ON applicant_scores TO authenticated, anon;
ALTER TABLE exam_interview_schedules DISABLE ROW LEVEL SECURITY;
GRANT SELECT, INSERT, UPDATE, DELETE ON exam_interview_schedules TO authenticated, anon;

BEGIN;

-- Full reset: wipe every data table (CASCADE clears dependents too).
TRUNCATE access_change_audit, applicant_attachments, applicant_scores, applicants, archives, assignments, competencies, competency_change_log, competency_dictionary, competency_requirement_proposals, cycle_compilations, departments, departments_backfill_audit, divisions, employee_competencies, employee_documents, employee_education, employee_eligibility, employee_history, employee_leave_balances, employee_portal_accounts, employee_settings, employee_training, employee_work_experience, employees, evaluation_cycles, evaluations, exam_interview_schedules, ipcr_notifications, ipcr_performance, ipcr_submissions, job_postings, jobs, locked_targets, new_entrant_onboarding, newly_hired, office_cycle_closeouts, office_role_assignments, performance_cycles, performance_evaluations, phase_schedules, pm_lnd_reports, policy_audit, position_competency_requirements, qualification_standards, raters, supervisor_password_resets, supervisors, training_enrollments, training_programs, training_requests, training_sessions, trainings, user_roles RESTART IDENTITY CASCADE;

-- departments (5)

-- divisions (20)

-- job_postings (30)

-- employees (25)

-- archives (20)

-- applicants (150)

-- applicant_scores (150)

-- exam_interview_schedules (150)

-- ── Regenerate employee login accounts from the freshly seeded employees ─────
-- The TRUNCATE above wipes employee_portal_accounts; without this step every
-- employee login would break. Creates one account per seeded employee:
--   username = employee_number   password = 'cictrix123'
-- employee_id is set to the employee_number so login resolves the Supabase
-- employees row (and thus supabaseId) — which the IPCR Workspace needs to save.
SELECT
  'portal-' || e.employee_number,
  e.employee_number,
  'cictrix123',
  e.employee_number,
  btrim(concat_ws(' ', e.first_name, e.middle_name, e.last_name)),
  e.email
FROM employees e
ON CONFLICT (id) DO NOTHING;

-- ── Seed one Supervisor office-role assignment per department ────────────────
-- office_role_assignments is TRUNCATEd above; the employee-portal "Switch
-- Account" icon is gated by an ACTIVE assignment for the logged-in employee, so
-- without this it would never appear. Makes the first employee (by number) in
-- each department a Supervisor, so switching to the Office dashboard is testable.
-- Log in as that employee (username = employee_number, password = 'cictrix123').
   must_change_password, status, assigned_by, assigned_at)
SELECT
  e.id,
  btrim(concat_ws(' ', e.first_name, e.middle_name, e.last_name)),
  e.department,
  'Supervisor',
  lower(replace(e.employee_number, '-', '_')) || '_office',
  'office123',
  false,
  'Active',
  'seed',
  now()
FROM (
  SELECT DISTINCT ON (department)
    id, first_name, middle_name, last_name, department, employee_number
  FROM employees
  WHERE department IS NOT NULL
  ORDER BY department, employee_number
) e;

COMMIT;
